import{_ as e,o as i,c as o,ag as l}from"./chunks/framework-C5-Jzrz4.js";const d=JSON.parse('{"title":"Resize 可拖拽缩放","description":"@vben/common-ui 的拖拽缩放容器，支持边界限制、吸附和比例控制","frontmatter":{"title":"Resize 可拖拽缩放","description":"@vben/common-ui 的拖拽缩放容器，支持边界限制、吸附和比例控制","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/resize.md","filePath":"scripts/components/common-ui/resize.md","lastUpdated":null}');const a=e({name:"scripts/components/common-ui/resize.md"},[["render",function(e,d,a,c,r,t){return i(),o("div",null,[...d[0]||(d[0]=[l('<h1 id="vresize" tabindex="-1"><code>VResize</code> <a class="header-anchor" href="#vresize" aria-label="Permalink to &quot;`VResize`&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>VResize</code> 是一个从 <code>vue-drag-resize</code> 思路演化出来的容器组件，适合做可拖拽、可缩放的面板或浮层。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>设计器中的可拖拽模块</li><li>浮动窗口或面板</li><li>需要在父容器内保持边界的自由布局</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/effects/common-ui/src/components/resize/index.ts</code></li><li><code>packages/effects/common-ui/src/components/resize/resize.vue</code></li></ul><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><ul><li><code>VResize</code></li></ul><h3 id="关键-props" tabindex="-1">关键 Props <a class="header-anchor" href="#关键-props" aria-label="Permalink to &quot;关键 Props&quot;">​</a></h3><ul><li><code>isActive</code></li><li><code>isDraggable</code></li><li><code>isResizable</code></li><li><code>aspectRatio</code></li><li><code>parentLimitation</code></li><li><code>snapToGrid</code></li><li><code>gridX</code></li><li><code>gridY</code></li><li><code>parentW</code></li><li><code>parentH</code></li><li><code>w</code></li><li><code>h</code></li><li><code>minw</code></li><li><code>minh</code></li><li><code>x</code></li><li><code>y</code></li><li><code>z</code></li><li><code>dragHandle</code></li><li><code>dragCancel</code></li><li><code>sticks</code></li><li><code>axis</code></li><li><code>contentClass</code></li></ul><h3 id="事件" tabindex="-1">事件 <a class="header-anchor" href="#事件" aria-label="Permalink to &quot;事件&quot;">​</a></h3><ul><li><code>clicked</code></li><li><code>dragging</code></li><li><code>dragstop</code></li><li><code>resizing</code></li><li><code>resizestop</code></li><li><code>activated</code></li><li><code>deactivated</code></li></ul><h2 id="使用方式与注意事项" tabindex="-1">使用方式与注意事项 <a class="header-anchor" href="#使用方式与注意事项" aria-label="Permalink to &quot;使用方式与注意事项&quot;">​</a></h2><ul><li><code>dragHandle</code> 和 <code>dragCancel</code> 都是选择器级控制，不是布尔开关。</li><li><code>axis</code> 支持 <code>both</code>、<code>none</code>、<code>x</code>、<code>y</code>。</li><li>开启 <code>aspectRatio</code> 后，缩放会按比例收敛，不再是纯自由宽高变化。</li><li>这是低层交互组件，适合做设计器，不适合替代普通布局容器。</li></ul>',16)])])}]]);export{d as __pageData,a as default};
